17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	const COMPONENT_PREMIUM = 25;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_PREMIUM = 60;
27	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
28	
29	const FIRST_INSURANCE_SURCHARGE = 1.1;
30	const CURSE_SURCHARGE_RATE = 0.5;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	const PROCESSING_FEE = 5;
34	
35	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
36	
37	const sum = (values: number[]): number => values.reduce((acc, value) => acc + value, 0);
38	
39	// Base premium of a single item (main item or one component).
40	const itemBase = (item: Item): number =>
41	  isComponent(item) ? COMPONENT_PREMIUM : (BASE_PREMIUM[item.type] ?? 0);
42	
43	// A surcharge adds `rate` of the base premium for each affected item.
44	const surchargeFor = (items: Item[], affects: (item: Item) => boolean, rate: number): number =>
45	  sum(items.filter(affects).map((item) => rate * itemBase(item)));
46	
47	// Curse adds 50% of the affected item's base premium.
48	const curseSurcharge = (items: Item[]): number =>
49	  surchargeFor(items, (item) => item.cursed === true, CURSE_SURCHARGE_RATE);
50	
51	// High enchantment (level >= 5) adds 30% of the affected item's base premium.
52	const enchantmentSurcharge = (items: Item[]): number =>
53	  surchargeFor(
54	    items,
55	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
56	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
57	  );
58	
59	// Base premium for `count` alike components: a group of exactly 3 forms a
60	// block at COMPONENT_BLOCK_PREMIUM; otherwise each component costs
61	// COMPONENT_PREMIUM.
62	const componentGroupPremium = (count: number): number =>
63	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
64	
65	// Count how many alike components of each type appear (e.g. { rune: 2 }).
66	const countByType = (items: Item[]): Map<string, number> =>
67	  items.reduce((counts, item) => {
68	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
69	    return counts;
70	  }, new Map<string, number>());
71	
72	const mainItemsPremium = (items: Item[]): number =>
73	  sum(items.filter((item) => !isComponent(item)).map(itemBase));
74	
75	const componentsPremium = (items: Item[]): number =>
76	  sum([...countByType(items.filter(isComponent)).values()].map(componentGroupPremium));
77	
78	const basePremium = (items: Item[]): number =>
79	  mainItemsPremium(items) + componentsPremium(items);
80	
81	// Round up to a whole number in MHPCO's favour, guarding against
82	// floating-point noise (e.g. 197.5000000001) before the ceiling by snapping
83	// to 6 decimal places first.
84	const FLOAT_GUARD_PRECISION = 1e6;
85	const roundUpToWhole = (value: number): number =>
86	  Math.ceil(Math.round(value * FLOAT_GUARD_PRECISION) / FLOAT_GUARD_PRECISION);
87	
88	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
89	  const results = scenario.steps.map((step) => {
90	    const base = basePremium(step.items);
91	    const premium =
92	      base * FIRST_INSURANCE_SURCHARGE +
93	      curseSurcharge(step.items) +
94	      enchantmentSurcharge(step.items) +
95	      PROCESSING_FEE;
96	    return { premium: roundUpToWhole(premium) };
97	  });
98	  return { results };
99	};
